class ErrorSeverity(Enum):
    LOW = "low"
    MEDIUM = "medium"
    HIGH = "high"
    CRITICAL = "critical"


class ErrorRegistry:
    """
    Server-side error registry that stores detailed error information.
    Clients receive only correlation IDs, never internal details.
    """

    def __init__(self):
        self._errors = {}
        self._max_entries = 10000

    def register_error(
        self,
        correlation_id: str,
        exception: Exception,
        internal_state: dict = None,
        severity: ErrorSeverity = ErrorSeverity.MEDIUM
    ) -> dict:
        """Register an error with full details server-side."""
        if len(self._errors) >= self._max_entries:
            # Remove oldest entries
            oldest_keys = sorted(
                self._errors.keys(),
                key=lambda k: self._errors[k]['timestamp']
            )[:1000]
            for key in oldest_keys:
                del self._errors[key]

        error_record = {
            'correlation_id': correlation_id,
            'timestamp': datetime.now(timezone.utc).isoformat(),
            'exception_type': type(exception).__name__,
            'exception_message': str(exception),
            'stack_trace': traceback.format_exc(),
            'internal_state': _sanitize_internal_state(internal_state or {}),
            'severity': severity.value,
        }

        self._errors[correlation_id] = error_record
        return error_record

    def get_error(self, correlation_id: str) -> dict:
        """Retrieve error details by correlation ID (server-side only)."""
        return self._errors.get(correlation_id)

    def get_recent_errors(self, count: int = 50) -> list:
        """Get recent errors for monitoring dashboards."""
        sorted_errors = sorted(
            self._errors.values(),
            key=lambda e: e['timestamp'],
            reverse=True
        )
        return sorted_errors[:count]


def _sanitize_internal_state(state: dict) -> dict:
    """
    Sanitize internal state before logging to prevent sensitive data
    from appearing even in server-side logs.
    """
    sensitive_keys = {
        'password', 'secret', 'token', 'api_key', 'apikey',
        'authorization', 'auth', 'credential', 'private_key',
        'ssn', 'social_security', 'credit_card', 'card_number',
        'cvv', 'pin', 'session_id', 'cookie'
    }

    sanitized = {}
    for key, value in state.items():
        lower_key = key.lower()
        if any(sensitive in lower_key for sensitive in sensitive_keys):
            sanitized[key] = '[REDACTED]'
        elif isinstance(value, dict):
            sanitized[key] = _sanitize_internal_state(value)
        elif isinstance(value, str) and len(value) > 500:
            sanitized[key] = value[:500] + '...[TRUNCATED]'
        else:
            sanitized[key] = value

    return sanitized


def generate_correlation_id() -> str:
    """Generate a unique correlation ID for error tracking."""
    return f"err-{uuid.uuid4().hex[:12]}-{int(time.time())}"


def create_safe_client_message(correlation_id: str, grpc_code: grpc.StatusCode) -> str:
    """
    Create a safe error message for the client that contains NO internal details.
    Only a correlation ID for support reference.
    """
    safe_messages = {
        grpc.StatusCode.INVALID_ARGUMENT: "Invalid request parameters.",
        grpc.StatusCode.NOT_FOUND: "The requested resource was not found.",
        grpc.StatusCode.ALREADY_EXISTS: "The resource already exists.",
        grpc.StatusCode.PERMISSION_DENIED: "Permission denied.",
        grpc.StatusCode.UNAUTHENTICATED: "Authentication required.",
        grpc.StatusCode.RESOURCE_EXHAUSTED: "Resource limit exceeded. Please retry later.",
        grpc.StatusCode.UNAVAILABLE: "Service temporarily unavailable. Please retry.",
        grpc.StatusCode.DEADLINE_EXCEEDED: "Request timed out. Please retry.",
        grpc.StatusCode.INTERNAL: "An internal error occurred.",
        grpc.StatusCode.UNIMPLEMENTED: "This operation is not supported.",
    }

    base_message = safe_messages.get(grpc_code, "An unexpected error occurred.")
    return f"{base_message} Reference ID: {correlation_id}"


# Global error registry instance
error_registry = ErrorRegistry()


def secure_error_handler(method_name: str):
    """
    Decorator for gRPC service methods that provides secure error handling.

    - Logs full error details server-side (including stack traces, internal state)
    - Returns ONLY a correlation ID and generic message to the client
    - Never exposes stack traces, internal state, or implementation details to clients
    """
    def decorator(func):
        def wrapper(self, request, context):
            correlation_id = generate_correlation_id()

            # Add correlation ID to context metadata for tracing
            context.set_trailing_metadata([
                ('x-correlation-id', correlation_id),
            ])

            try:
                return func(self, request, context)

            except ValueError as e:
                _handle_error(
                    correlation_id=correlation_id,
                    exception=e,
                    context=context,
                    grpc_code=grpc.StatusCode.INVALID_ARGUMENT,
                    method_name=method_name,
                    severity=ErrorSeverity.LOW,
                    internal_state=_extract_safe_request_info(request),
                )
                return SimpleResponse(message="", status_code=400)

            except PermissionError as e:
                _handle_error(
                    correlation_id=correlation_id,
                    exception=e,
                    context=context,
                    grpc_code=grpc.StatusCode.PERMISSION_DENIED,
                    method_name=method_name,
                    severity=ErrorSeverity.HIGH,
                    internal_state=_extract_safe_request_info(request),
                )
                return SimpleResponse(message="", status_code=403)

            except FileNotFoundError as e:
                _handle_error(
                    correlation_id=correlation_id,
                    exception=e,
                    context=context,
                    grpc_code=grpc.StatusCode.NOT_FOUND,
                    method_name=method_name,
                    severity=ErrorSeverity.LOW,
                    internal_state=_extract_safe_request_info(request),
                )
                return SimpleResponse(message="", status_code=404)

            except TimeoutError as e:
                _handle_error(
                    correlation_id=correlation_id,
                    exception=e,
                    context=context,
                    grpc_code=grpc.StatusCode.DEADLINE_EXCEEDED,
                    method_name=method_name,
                    severity=ErrorSeverity.MEDIUM,
                    internal_state=_extract_safe_request_info(request),
                )
                return SimpleResponse(message="", status_code=504)

            except ConnectionError as e:
                _handle_error(
                    correlation_id=correlation_id,
                    exception=e,
                    context=context,
                    grpc_code=grpc.StatusCode.UNAVAILABLE,
                    method_name=method_name,
                    severity=ErrorSeverity.HIGH,
                    internal_state=_extract_safe_request_info(request),
                )
                return SimpleResponse(message="", status_code=503)

            except NotImplementedError as e:
                _handle_error(
                    correlation_id=correlation_id,
                    exception=e,
                    context=context,
                    grpc_code=grpc.StatusCode.UNIMPLEMENTED,
                    method_name=method_name,
                    severity=ErrorSeverity.LOW,
                    internal_state=_extract_safe_request_info(request),
                )
                return SimpleResponse(message="", status_code=501)

            except Exception as e:
                # Catch-all for unexpected exceptions
                _handle_error(
                    correlation_id=correlation_id,
                    exception=e,
                    context=context,
                    grpc_code=grpc.StatusCode.INTERNAL,
                    method_name=method_name,
                    severity=ErrorSeverity.CRITICAL,
                    internal_state=_extract_safe_request_info(request),
                )
                return SimpleResponse(message="", status_code=500)

        return wrapper
    return decorator


def _handle_error(
    correlation_id: str,
    exception: Exception,
    context,
    grpc_code: grpc.StatusCode,
    method_name: str,
    severity: ErrorSeverity,
    internal_state: dict = None,
):
    """
    Central error handling: logs everything server-side, sends minimal info to client.
    """
    # Register full error details in server-side registry
    error_record = error_registry.register_error(
        correlation_id=correlation_id,
        exception=exception,
        internal_state={
            'method': method_name,
            'request_info': internal_state or {},
            'server_pid': os.getpid(),
        },
        severity=severity,
    )

    # Log full details server-side for debugging
    logger.error(
        "gRPC Error [%s] in method '%s': %s: %s",
        correlation_id,
        method_name,
        type(exception).__name__,
        str(exception),
    )
    logger.debug(
        "Full error record [%s]: %s",
        correlation_id,
        json.dumps(error_record, indent=2, default=str),
    )

    if severity in (ErrorSeverity.HIGH, ErrorSeverity.CRITICAL):
        logger.critical(
            "ALERT: %s severity error [%s] in %s - requires attention",
            severity.value,
            correlation_id,
            method_name,
        )

    # Send ONLY safe, generic message to client - no internal details
    safe_message = create_safe_client_message(correlation_id, grpc_code)
    context.set_code(grpc_code)
    context.set_details(safe_message)


def _extract_safe_request_info(request) -> dict:
    """
    Extract non-sensitive information from a request for logging.
    Never include credentials, tokens, or PII.
    """
    safe_info = {}
    try:
        if hasattr(request, 'name'):
            # Don't log the actual value if it could be PII
            safe_info['has_name'] = bool(request.name)
            safe_info['name_length'] = len(request.name) if request.name else 0
        if hasattr(request, 'value'):
            safe_info['has_value'] = request.value is not None
        safe_info['request_type'] = type(request).__name__
    except Exception:
        safe_info['extraction_error'] = True
    return safe_info


class SecureExampleService:
    """
    Example gRPC service demonstrating secure error handling patterns.

    Key principles:
    1. Never send stack traces to clients
    2. Never send internal state to clients
    3. Use correlation IDs for cross-referencing
    4. Log full details server-side only
    5. Sanitize even server-side logs for credentials
    """

    @secure_error_handler("GetUser")
    def GetUser(self, request, context):
        """Example: Get user by name."""
        if not request.name:
            raise ValueError("Name parameter is required")

        if request.name == "admin":
            raise PermissionError("Cannot access admin user via this endpoint")

        if request.name == "nonexistent":
            raise FileNotFoundError(f"User not found")

        if request.name == "slow":
            raise TimeoutError("Database query timed out")

        if request.name == "dbdown":
            raise ConnectionError("Failed to connect to database")

        if request.name == "crash":
            # Simulate unexpected error - client will only see generic message
            internal_data = {"db_host": "prod-db-01.internal", "query": "SELECT * FROM users"}
            _ = internal_data
            raise RuntimeError("Segfault in native extension at 0xDEADBEEF")

        return SimpleResponse(
            message=f"Hello, {request.name}!",
            status_code=200
        )

    @secure_error_handler("ProcessPayment")
    def ProcessPayment(self, request, context):
        """Example: Process a payment - demonstrates sensitive data handling."""
        # Even if an error occurs, credit card details must never leak
        internal_state = {
            'credit_card': '4111-1111-1111-1111',  # Would be redacted in logs
            'api_key': 'sk_live_abc123',  # Would be redacted in logs
            'amount': request.value,
        }
        _ = internal_state

        if request.value <= 0:
            raise ValueError("Payment amount must be positive")

        if request.value > 10000:
            raise PermissionError("Amount exceeds authorized limit")

        return SimpleResponse(message="Payment processed", status_code=200)

    @secure_error_handler("ExperimentalFeature")
    def ExperimentalFeature(self, request, context):
        """Example: Unimplemented feature."""
        raise NotImplementedError("This feature is not yet available")


